css:
* { margin: 0; padding: 0; box-sizing: border-box; }
 body { font-family: 'Courier New', monospace; font-size: 11px; padding: 24px 32px; }
  .report-meta { display: flex; justify-content: space-between; margin-bottom: 16px; }
  .company-name { font-weight: bold; font-size: 12px; }
  .meta-info td:nth-child(2) { padding: 0 6px; }
  .report-title { text-align: center; margin-bottom: 4px; }
  .report-title h2 { font-size: 14px; letter-spacing: 6px; text-transform: uppercase; }
  .report-periode { text-align: center; font-size: 11px; margin-top: 3px; }
 table.data-table { width: 100%; border-collapse: collapse; margin-top: 12px; }
 table.data-table th, table.data-table td { border: 1px solid #000; padding: 3px 5px; font-size: 10px; }
 table.data-table th { background: #f0f0f0; text-align: center; }
  .grand-total { margin-top: 10px; text-align: center; font-weight: bold; }
  .ttd { display: flex; justify-content: space-between; margin-top: 40px; }
